# ── Helpers ───────────────────────────────────────────────────────────────────

def norm(t):
    t = str(t).upper().strip()
    for a,b in [("Á","A"),("É","E"),("Í","I"),("Ó","O"),("Ú","U"),("Ü","U"),("Ñ","N")]:
        t = t.replace(a,b)
    return t

def parse_fecha(v):
    if not v: return None
    v = str(v).strip()
    # "13 de septiembre de 1990"
    meses = {"enero":1,"febrero":2,"marzo":3,"abril":4,"mayo":5,"junio":6,
             "julio":7,"agosto":8,"septiembre":9,"octubre":10,"noviembre":11,"diciembre":12}
    m = re.search(r'(\d{1,2})\s+de\s+(\w+)\s+de\s+(\d{4})', v, re.I)
    if m:
        mes = meses.get(m.group(2).lower())
        if mes:
            try: return datetime(int(m.group(3)), mes, int(m.group(1))).strftime("%Y-%m-%d")
            except: pass
    for fmt in ("%d/%m/%Y","%d-%m-%Y","%Y-%m-%d","%d.%m.%Y"):
        try: return datetime.strptime(v, fmt).strftime("%Y-%m-%d")
        except: pass
    return None

def limpiar_tel(v):
    d = re.sub(r"[^\d]","",str(v))
    if d.startswith("34") and len(d)==11: d=d[2:]
    return d[:9]

def limpiar_nif(v):
    return re.sub(r"[-\s]","",str(v)).upper()

def a_bool(v):
    if v is None: return False
    s = norm(str(v))
    return s in ("TRUE","SI","S","ACEPTO","X","1","VERDADERO")

# ── Mapeo etiqueta PDF → clave interna ────────────────────────────────────────
# Trabaja con la etiqueta ya normalizada (sin tildes, mayúsculas)

def mapear(etq: str) -> str | None:
    e = norm(etq)
    # Curso
    if "NUMERO EXPEDIENTE"    in e: return "NUM_EXPEDIENTE"
    if "CONVOCATORIA"         in e and "NRO" not in e: return "CONVOCATORIA"
    if "ENTIDAD REPRESENTANT" in e: return "ENTIDAD_REP"
    if "ENTIDAD FORMADORA"    in e: return "ENTIDAD_FORM"
    if e.startswith("PROGRAMA") and "EDICION" not in e: return "PROGRAMA"
    if "EDICION"              in e: return "EDICION"
    if "CCAA CURSO"           in e: return "CCAA_CURSO"
    if "PROVINCIA CURSO"      in e: return "PROV_CURSO"
    if "LOCALIDAD CURSO"      in e: return "LOCAL_CURSO"
    if "MODALIDAD"            in e: return "MODALIDAD"
    if "FECHA" in e and "INICIO" in e: return "FECHA_INICIO"
    if "FECHA" in e and "FIN"   in e: return "FECHA_FIN"
    if "AMBITO CURSO"         in e: return "AMBITO_CURSO"
    # Personales
    if "PRIMER APELLIDO"      in e: return "APELLIDO1"
    if "SEGUNDO APELLIDO"     in e: return "APELLIDO2"
    if e.startswith("NOMBRE") and "EMPRESA" not in e: return "NOMBRE"
    if "TIPO DE DOCUMENTO"    in e: return "_RAWDOC1"  # puede ser tipo o número según plantilla
    if e.startswith("N") and "DOCUMENTO" in e and "TIPO" not in e and "NIF" not in e: return "_RAWDOC2"
    if "SEXO"                 in e: return "SEXO"
    if "FECHA DE NACIMIENTO"  in e or "NACIMIENTO" in e: return "FECHA_NAC"
    if e.startswith("DIRECCION") and "EMPRESA" not in e: return "DIRECCION"
    if e.startswith("CIUDAD") and "EMPRESA" not in e: return "CIUDAD"
    if "CODIGO POSTAL" in e and "EMPRESA" not in e: return "CP"
    if e.startswith("CCAA") and "EMPRESA" not in e and "CURSO" not in e: return "CCAA"
    if e.startswith("PROVINCIA") and "EMPRESA" not in e and "CURSO" not in e: return "PROVINCIA"
    if "TELEFONO" in e and "EMPRESA" not in e: return "TELEFONO"
    if e.startswith("EMAIL") or e.startswith("CORREO"): return "EMAIL"
    if "5.000" in e or "5000" in e or "HABITANTES INFERIOR" in e: return "RURAL_PERS"
    if "DISCAPACIDAD" in e and "ACEPTO" not in e: return "DISCAPACIDAD"
    if "LINKEDIN" in e: return "LINKEDIN"
    if "NIVEL DE ESTUDIOS" in e or e.startswith("NIVEL DE ESTUDIO"): return "NIVEL_EST"
    if "TITULACION" in e: return "TITULACION"
    if "RELACION CON LA EMPRESA" in e or "RELACION CON EMPRESA" in e: return "RELACION"
    # Profesionales
    if "DEPARTAMENTO" in e: return "DEPTO"
    if "PUESTO" in e or "CARGO" in e: return "CARGO"
    if "SITUACION LABORAL" in e: return "SIT_LAB"
    if "EXPERIENCIA LABORAL EN" in e or "PUESTOS DE DIGITAL" in e: return "EXP_DIGIT"
    if "EXPERIENCIA LABORAL" in e or "ANOS DE EXPERIENCIA" in e: return "EXP_LAB"
    if "FORMACION" in e and "DIGITAL" in e and "EMPRESA" not in e: return "FORM_DIGIT"
    if "FORMACION" in e and ("GESTION" in e or "PROYECTO" in e): return "FORM_PROY"
    if "NIVEL DE ESTUDIOS" in e or e.startswith("NIVEL DE ESTUDIO"): return "NIVEL_EST"
    # Empresa
    if "NOMBRE EMPRESA" in e or "RAZON SOCIAL" in e: return "EMP_NOMBRE"
    if "NIF EMPRESA" in e: return "EMP_NIF"
    if "ACTIVIDAD DE LA EMPRESA" in e or "CNAE" in e: return "EMP_CNAE"
    if "TAMANO EMPRESA" in e or "TAMANIO EMPRESA" in e: return "EMP_TAM"
    if "DIRECCION" in e and "EMPRESA" in e: return "EMP_DIR"
    if "CIUDAD" in e and "EMPRESA" in e: return "EMP_CIUDAD"
    if "CODIGO POSTAL" in e and "EMPRESA" in e: return "EMP_CP"
    if "CCAA" in e and "EMPRESA" in e: return "EMP_CCAA"
    if "PROVINCIA" in e and "EMPRESA" in e: return "EMP_PROV"
    if "TELEFONO" in e and "EMPRESA" in e: return "EMP_TEL"
    if "PAGINA WEB" in e or "WEB" in e and "EMPRESA" in e: return "EMP_WEB"
    if "ANTIGUEDAD" in e: return "EMP_ANT"
    if "FACTURACION" in e or "FACTUR" in e: return "EMP_FACT"
    if "AMBITO RURAL" in e: return "EMP_RURAL"
    if "MADUREZ DIGITAL" in e: return "EMP_MADUREZ"
    if "CANALES DE RELACION" in e: return "EMP_CANALES"
    if "PERFIL TIC" in e: return "EMP_TIC"
    if "SOSTENIBILIDAD" in e: return "EMP_SOST"
    if "TRANSFORMACION DIGITAL" in e and "EMPRESA" in e: return "EMP_TRANSF"
    if "MAXIMA RESPONSABLE" in e or ("EQUIPO DIRECTIVO" in e and "MUJER" in e): return "EMP_MUJER_DIR"
    if "PORCENTAJE DE MUJERES" in e: return "EMP_PCT_MUJ"
    # Declaraciones pág 2
    if "ACEPTO" in e and "TERMINOS" in e: return "ACEPTO_COND"
    if "CALIFICAN COMO PYME" in e or ("PYME" in e and "DECLARO" in e): return "DECLARO_PYME"
    if "NO HE RECIBIDO" in e or "MISMA FORMACION" in e: return "DECLARO_FORM"
    if "DATO RELATIVO" in e or ("DISCAPACIDAD" in e and "ACEPTO" in e): return "ACEPTO_DISC"
    if "AUTORIZO" in e and "TRATAMIENTO" in e: return "AUTORIZO"
    return None

# ── Extracción PDF ─────────────────────────────────────────────────────────────

def extraer_campos(ruta: str) -> dict:
    campos = {}
    try:
        with pdfplumber.open(ruta) as pdf:
            for page in pdf.pages:
                for tabla in page.extract_tables():
                    ultima_k = None
                    for fila in tabla:
                        if not fila or len(fila) < 2: continue
                        etq = str(fila[0] or "").replace("\n"," ").strip()
                        val = str(fila[1] or "").replace("\n"," ").strip()
                        if not val: 
                            ultima_k = mapear(etq) if etq else ultima_k
                            continue
                        # Fila sin etiqueta justo tras FORM_DIGIT → es FORM_PROY
                        if not etq and ultima_k == "FORM_DIGIT":
                            if "FORM_PROY" not in campos:
                                campos["FORM_PROY"] = val
                            ultima_k = None
                            continue
                        if not etq: continue
                        k = mapear(etq)
                        if k and k not in campos:
                            campos[k] = val
                        ultima_k = k
    except Exception:
        pass

    # Resolver cruce TIPO_DOC / NIF:
    # _RAWDOC1 = valor de fila "TIPO DE DOCUMENTO"
    # _RAWDOC2 = valor de fila "Nº de Documento"
    raw1 = campos.pop("_RAWDOC1", "")
    raw2 = campos.pop("_RAWDOC2", "")
    _TIPOS = {"NIF","NIE","PASAPORTE","PASSPORT","DNI"}
    def es_tipo(v): return norm(v) in _TIPOS
    def es_num(v): return bool(re.search(r'[0-9]', v))
    if raw1 and raw2:
        if es_tipo(raw1) and es_num(raw2):
            campos.setdefault("TIPO_DOC", raw1)
            campos.setdefault("NIF", raw2)
        elif es_num(raw1) and es_tipo(raw2):
            campos.setdefault("NIF", raw1)
            campos.setdefault("TIPO_DOC", raw2)
        else:
            campos.setdefault("TIPO_DOC", raw2)
            campos.setdefault("NIF", raw1)
    elif raw1:
        if es_tipo(raw1): campos.setdefault("TIPO_DOC", raw1)
        else:             campos.setdefault("NIF", raw1)
    elif raw2:
        if es_tipo(raw2): campos.setdefault("TIPO_DOC", raw2)
        else:             campos.setdefault("NIF", raw2)

    return campos

# ── Normalizadores de desplegable ─────────────────────────────────────────────

_CCAA = ["Andalucía","Aragón","Baleares","Canarias","Cantabria","Castilla y León",
         "Castilla-La Mancha","Cataluña","Comunidad de Madrid","Comunidad Foral de Navarra",
         "Comunidad Valenciana","Extremadura","Galicia","La Rioja","País Vasco",
         "Principado de Asturias","Región de Murcia"]
def norm_ccaa(v):
    n = norm(v)
    for x in _CCAA:
        if norm(x) in n or n in norm(x): return x
    return v or None

_PROVINCIAS = [
    "ÁLAVA (ARABA)","ALBACETE","ALICANTE (ALACANT)","ALMERÍA","ASTURIAS","ÁVILA",
    "BADAJOZ","BARCELONA","BURGOS","CÁCERES","CÁDIZ","CANTABRIA","CASTELLÓN (CASTELLÓ)",
    "CEUTA","CIUDAD REAL","CÓRDOBA","CUENCA","GERONA (GIRONA)","GRANADA","GUADALAJARA",
    "GUIPÚZCOA (GIPUZKOA)","HUELVA","HUESCA","ISLAS BALEARES (ILLES BALEARS)","JAÉN",
    "LA CORUÑA (A CORUÑA)","LA RIOJA","LAS PALMAS DE GC","LEÓN","LÉRIDA (LLEIDA)",
    "LUGO","MADRID","MÁLAGA","MELILLA","MURCIA","NAVARRA","ORENSE (OURENSE)","PALENCIA",
    "PONTEVEDRA","SALAMANCA","SANTA CRUZ DE TENERIFE","SEGOVIA","SEVILLA","SORIA",
    "TARRAGONA","TERUEL","TOLEDO","VALENCIA","VALLADOLID","VIZCAYA (BIZKAIA)",
    "ZAMORA","ZARAGOZA",
]
def norm_provincia(v):
    if not v or not str(v).strip(): return None
    n = norm(v)
    if not n: return None
    for x in _PROVINCIAS:
        if norm(x) == n: return x
    partes = n.split()
    if partes:
        for x in _PROVINCIAS:
            primera = norm(x).split()[0].rstrip("(")
            if primera and primera == partes[0]: return x
    return v or None

def norm_modalidad(v):
    n = norm(v)
    if "PRESENCIAL" in n: return "Presencial"
    if "BIMODAL"    in n: return "Bimodal"
    if "MIXTA"      in n: return "Mixta"
    return v or None

def norm_tipo_doc(v):
    n = norm(v)
    if "NIE" in n: return "NIE"
    if "PAS" in n: return "Pasaporte"
    return "NIF"

def norm_sexo(v):
    n = norm(v).strip()
    if n in ("M","HOMBRE","MASCULINO"): return "M"
    if n in ("F","MUJER","FEMENINO"):   return "F"
    return "NB" if "NB" in n else (v or None)

_NIVEL_DIR = [
    "Enseñanza primaria (CINE 1)",
    "Primer ciclo de Enseñanza Secundaria: ESO o equivalente (CINE 2)",
    "Segundo ciclo de Enseñanza Secundaria: FP Básica, FP Grado Medio Bachillerato (CINE 3)",
    "Enseñanza postsecundaria no terciaria (CINE 4)",
    "Estudios Universitarios y FP Grado Superior o equivalente (CINE 5 a 7)",
]
def norm_nivel_dir(v):
    n = norm(v)
    if "CINE 1" in n or ("PRIMARIA" in n and "CINE" not in n): return _NIVEL_DIR[0]
    if "CINE 2" in n or "ESO" in n: return _NIVEL_DIR[1]
    if "CINE 3" in n or "BACHILLER" in n or "GRADO MEDIO" in n or "FP BASICA" in n: return _NIVEL_DIR[2]
    if "CINE 4" in n or "POSTSECUND" in n: return _NIVEL_DIR[3]
    if "CINE 5" in n or "CINE 6" in n or "CINE 7" in n or "UNIVERSITARI" in n or "GRADO SUPERIOR" in n: return _NIVEL_DIR[4]
    # Si ya viene el texto exacto, devolverlo tal cual
    for x in _NIVEL_DIR:
        if norm(x) in n or n in norm(x): return x
    return v or None

_NIVEL_AGE = [
    "Certificado de profesionalidad de nivel 3, y experiencia laboral mínima de 2 años en un puesto en competencias digitales",
    "Título de Bachillerato y experiencia laboral mínima de 2 años en un puesto en competencias digitales",
    "Título de FP Grado Medio y experiencia laboral mínima de 2 años en un puesto en competencias digitales",
    "Cursando último año de carrera",
    "Título de Grado Universitario",
    "Título de FP Grado Superior.",
]
def norm_nivel_age(v):
    n = norm(v)
    if "CERTIFICADO" in n: return _NIVEL_AGE[0]
    if "BACHILLER"   in n: return _NIVEL_AGE[1]
    if "GRADO MEDIO" in n or "FP MEDIO" in n: return _NIVEL_AGE[2]
    if "CURSANDO"    in n: return _NIVEL_AGE[3]
    if "GRADO UNIVERSITARIO" in n or "GRADO UNIVERSI" in n: return _NIVEL_AGE[4]
    if "GRADO SUPERIOR" in n or "FP SUPERIOR" in n: return _NIVEL_AGE[5]
    for x in _NIVEL_AGE:
        if norm(x) in n or n in norm(x): return x
    return v or None

_RELACION = [
    "Directivo/a miembro del Comité de Dirección",
    "Relación con el capital de la empresa (socio, hijo...)",
    "Responsable de un área/departamento de la empresa",
]
def norm_relacion(v):
    n = norm(v)
    if "COMITE" in n or "MIEMBRO" in n: return _RELACION[0]
    if "CAPITAL" in n or "SOCIO" in n:  return _RELACION[1]
    if "RESPONSABLE" in n or "AREA" in n or "DEPARTAMENTO" in n: return _RELACION[2]
    return v or None

def norm_tamano(v, tipo="directivos"):
    n = norm(v)
    if tipo == "agentes" and "AUTONOMO" in n: return "Autónomo"
    nums = re.findall(r'\d+', n)
    if nums:
        num = int(nums[0])
        if num <= 9:   return "1 - 9 trabajadores"
        if num <= 49:  return "10 - 49 trabajadores"
        return "50 - 249 trabajadores"
    return v or None

def norm_antiguedad(v):
    n = norm(v)
    if ("ULTIMO" in n or "RECIEN" in n) and "5" in n: return "últimos 5 años"
    if "5" in n and "10" in n:  return "5 - 10 años"
    if "+ 10" in n or "+10" in n or ("MAS" in n and "10" in n): return "+ 10 años"
    # Si ya viene el texto exacto
    for x in ["últimos 5 años","5 - 10 años","+ 10 años"]:
        if norm(x) in n: return x
    return v or None

_FACT = ["0 - 500.000€","500.000€ - 1M€","1 - 2 M€","2 - 4 M€","+ 4 M€"]
def norm_facturacion(v):
    n = norm(v)
    for f in _FACT:
        if norm(f).replace("€","") in n.replace("€","") or norm(f) in n: return f
    if "500" in n and "1M" not in n and "1 M" not in n: return _FACT[0]
    if "500" in n and ("1M" in n or "1 M" in n): return _FACT[1]
    if "1" in n and "2 M" in n: return _FACT[2]
    if "2" in n and "4 M" in n: return _FACT[3]
    if "+ 4" in n: return _FACT[4]
    return v or None

def norm_madurez(v):
    n = norm(v)
    if "MUY BAJO" in n: return "Muy bajo"
    if "MUY ALTO" in n: return "Muy alto"
    if "BAJO" in n:     return "Bajo"
    if "ALTO" in n:     return "Alto"
    return v or None

def norm_canales(v):
    n = norm(v)
    if "ECOMMERCE" in n or "MARKETPLACE" in n: return "Ecommerce / Marketplace"
    if "WEB" in n or "PAGINA" in n: return "Página WEB"
    if "NINGUNO" in n: return "Ninguno"
    return v or None

def norm_tic(v):
    n = norm(v)
    if "NINGUN" in n: return "Ningún especialista"
    if "AL MENOS" in n or "ESPECIALISTA" in n: return "Al menos un especialista"
    return v or None

def norm_pct_muj(v):
    n = norm(v)
    if "INFERIOR" in n or ("30" in n and "ENTRE" not in n and "SUPERIOR" not in n): return "inferior a 30%"
    if "ENTRE" in n and "30" in n and "50" in n: return "entre 30% y 50%"
    if "SUPERIOR" in n or ("50" in n and "ENTRE" not in n): return "superior a 50%"
    return v or None

def norm_exp_lab(v):
    n = norm(v)
    if "+ 2" in n or "+2" in n: return "+ 2 años"
    if "6 MES" in n: return "6 meses - 2 años"
    return v or None

def norm_exp_digit(v):
    n = norm(v)
    if "SIN"   in n: return "Sin experiencia"
    if "MENOS" in n and "6" in n: return "menos de 6 meses"
    if "6 MES" in n and "1" in n: return "6 meses - 1 año"
    if "+ 1"   in n: return "+ 1 año"
    return v or None

def norm_sit_lab(v):
    n = norm(v)
    if "DESEMPL" in n: return "Desempleado"
    if "AUTONOMO" in n or "EMPRESARIO" in n: return "Autónomo/a - Empresario/a"
    if "CUENTA AJENA" in n or "EMPLEADO" in n: return "Empleado/a por cuenta ajena"
    return v or None

def norm_cnae(v):
    n = norm(v)
    m = re.search(r'\b([A-U])\s*[-–]', n)
    if m: return m.group(1)
    if re.match(r'^[A-U]$', n.strip()): return n.strip()
    return v or None

def normalizar(campos: dict, tipo: str) -> dict:
    c = dict(campos)
    g = lambda k: c.get(k,"") or ""

    c["CCAA_CURSO"]  = norm_ccaa(g("CCAA_CURSO"))
    c["CCAA"]        = norm_ccaa(g("CCAA"))
    c["EMP_CCAA"]    = norm_ccaa(g("EMP_CCAA"))
    c["PROV_CURSO"]  = norm_provincia(g("PROV_CURSO"))
    c["PROVINCIA"]   = norm_provincia(g("PROVINCIA"))
    c["EMP_PROV"]    = norm_provincia(g("EMP_PROV"))
    c["MODALIDAD"]   = norm_modalidad(g("MODALIDAD"))
    c["TIPO_DOC"]    = norm_tipo_doc(g("TIPO_DOC"))
    c["SEXO"]        = norm_sexo(g("SEXO"))
    c["NIVEL_EST"]   = norm_nivel_age(g("NIVEL_EST")) if tipo=="agentes" else norm_nivel_dir(g("NIVEL_EST"))
    c["EMP_CNAE"]    = norm_cnae(g("EMP_CNAE"))
    c["EMP_TAM"]     = norm_tamano(g("EMP_TAM"), tipo)
    c["EMP_ANT"]     = norm_antiguedad(g("EMP_ANT"))
    c["EMP_FACT"]    = norm_facturacion(g("EMP_FACT"))
    c["EMP_MADUREZ"] = norm_madurez(g("EMP_MADUREZ"))
    c["EMP_PCT_MUJ"] = norm_pct_muj(g("EMP_PCT_MUJ"))

    if tipo == "directivos":
        c["RELACION"]    = norm_relacion(g("RELACION"))
        c["EMP_CANALES"] = norm_canales(g("EMP_CANALES"))
        c["EMP_TIC"]     = norm_tic(g("EMP_TIC"))
    else:
        c["EXP_LAB"]    = norm_exp_lab(g("EXP_LAB"))
        c["EXP_DIGIT"]  = norm_exp_digit(g("EXP_DIGIT"))
        c["SIT_LAB"]    = norm_sit_lab(g("SIT_LAB"))
        raw = g("DECLARO_PYME")
        c["DECLARO_PYME"] = "NO PROCEDE" if "PROCEDE" in norm(str(raw)) else True
    return c

